import r from"./BtB9qa4J.js";import{_ as o}from"./DP2xkfOx.js";import{e as n,c as l,a as e,b as a,w as d,H as c,o as p,_ as m}from"./Dfh8yOmt.js";const f={class:"min-h-screen bg-slate-50 font-inter text-slate-800"},u={class:"border-b border-slate-200 bg-white/80 backdrop-blur-md sticky top-0 z-50"},x={class:"max-w-4xl mx-auto px-6 h-16 flex items-center justify-between"},v={class:"max-w-4xl mx-auto px-6 py-20"},b={class:"bg-white rounded-[2.5rem] p-10 md:p-20 shadow-xl shadow-slate-200/50 border border-slate-200 space-y-12 overflow-hidden relative"},g={class:"border-b border-slate-100 pb-12 relative z-10"},h={class:"w-16 h-16 bg-amber-50 rounded-2xl flex items-center justify-center mb-8 border border-amber-200 shadow-sm animate-pulse-slow"},y=n({__name:"risk-disclosure",setup(k){return(w,t)=>{const s=r,i=o;return p(),l("div",f,[e("nav",u,[e("div",x,[a(i,{to:"/welcome",class:"flex items-center gap-2 group"},{default:d(()=>[a(s,{name:"lucide:arrow-left",size:"18",class:"group-hover:-translate-x-1 transition-transform"}),t[0]||(t[0]=e("span",{class:"font-bold text-sm"},"Back to Home",-1))]),_:1}),t[1]||(t[1]=e("span",{class:"text-[10px] font-black uppercase tracking-widest text-slate-400"},"WiseKings Risk Advisory",-1))])]),e("main",v,[e("div",b,[t[4]||(t[4]=e("div",{class:"absolute -top-24 -right-24 w-64 h-64 bg-amber-50 rounded-full blur-3xl opacity-50"},null,-1)),e("header",g,[e("div",h,[a(s,{name:"lucide:alert-triangle",class:"text-amber-600",size:"32"})]),t[2]||(t[2]=e("h1",{class:"text-4xl md:text-5xl font-black text-slate-900 mb-4 tracking-tighter uppercase"},"Risk Disclosure",-1)),t[3]||(t[3]=e("p",{class:"text-slate-500 font-bold text-sm italic"},"All partners must read and acknowledge these risks before capital commitment.",-1))]),t[5]||(t[5]=c('<section class="space-y-12 text-slate-600 leading-relaxed relative z-10" data-v-949880f5><div class="p-8 bg-slate-50 rounded-3xl border border-slate-100 font-medium italic text-slate-700" data-v-949880f5> &quot;WiseKings Africa maintains a perfect repayment record for over 3 years, but past performance is never a guarantee of future returns. Business participation involves inherent risks that every partner must understand.&quot; </div><div class="grid grid-cols-1 md:grid-cols-2 gap-10" data-v-949880f5><div class="space-y-4" data-v-949880f5><h2 class="text-xl font-black text-slate-900 uppercase tracking-tight flex items-center gap-3" data-v-949880f5><span class="w-2 h-2 bg-amber-500 rounded-full" data-v-949880f5></span> 1. Cycle Interruption Risk </h2><p class="text-sm" data-v-949880f5>Commodity trade cycles (Gold Tier) are subject to logistical and supply chain factors. While rare, extreme events like port strikes or regional instability can extend a 60-day cycle. Capital is always prioritized, but profit timing may vary.</p></div><div class="space-y-4" data-v-949880f5><h2 class="text-xl font-black text-slate-900 uppercase tracking-tight flex items-center gap-3" data-v-949880f5><span class="w-2 h-2 bg-amber-500 rounded-full" data-v-949880f5></span> 2. Asset Liquidity Risk </h2><p class="text-sm" data-v-949880f5>Once capital is committed to a purchase order, it is deployed into physical inventory. This capital is illiquid until the inventory is sold and the cycle concludes. Early withdrawals are not permitted to maintain system stability for all partners.</p></div><div class="space-y-4" data-v-949880f5><h2 class="text-xl font-black text-slate-900 uppercase tracking-tight flex items-center gap-3" data-v-949880f5><span class="w-2 h-2 bg-indigo-500 rounded-full" data-v-949880f5></span> 3. Equity Valuation Risk </h2><p class="text-sm" data-v-949880f5>Diamond Tier shareholders face market-driven valuation risks. The the price of private equity is determined by company performance, expansion success, and overall sector appetite. Equity should be viewed as a 3-5 year horizon commitment.</p></div><div class="space-y-4" data-v-949880f5><h2 class="text-xl font-black text-slate-900 uppercase tracking-tight flex items-center gap-3" data-v-949880f5><span class="w-2 h-2 bg-indigo-500 rounded-full" data-v-949880f5></span> 4. Operational Risk </h2><p class="text-sm" data-v-949880f5>WiseKings operates across multiple jurisdictions. Regulatory changes in local markets regarding snacks import/export or financial technology can impact operational overhead and net margins.</p></div></div><div class="p-8 bg-slate-900 text-white rounded-[2rem] space-y-4" data-v-949880f5><h3 class="text-lg font-black uppercase tracking-widest text-amber-400" data-v-949880f5>Prudent Participation</h3><p class="text-sm text-slate-400 leading-relaxed" data-v-949880f5> We strongly advise all partners to diversify their participation. Invest only capital that you can afford to commit for the specified durations. If you are unsure of your financial standing, please consult with a certified financial advisor before joining. </p></div></section><footer class="mt-20 pt-10 border-t border-slate-100 flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-slate-300" data-v-949880f5><p data-v-949880f5>Doc Ref: WK-RD-2026-FINAL</p><p data-v-949880f5>Risk Management Department</p></footer>',2))])])])}}}),z=m(y,[["__scopeId","data-v-949880f5"]]);export{z as default};
